+            veb.insert(v);
+            reference.insert(v);
+        }
+
+        // Remove in reverse order
+        for &v in vals.iter().rev() {
+            let veb_had = veb.remove(v);
+            let ref_had = reference.remove(&v);
+            prop_assert_eq!(veb_had, ref_had, "remove({}) mismatch", v);
+        }
+    }
