+        let mut veb = VanEmdeBoas::new(256);
+        for &v in &vals {
+            veb.insert(v);
+        }
+
+        if reference.is_empty() {
+            return Ok(());
+        }
+
+        // Walk successor chain from min
+        let mut current = veb.min();
+        let mut chain = Vec::new();
+        while let Some(val) = current {
+            chain.push(val);
+            current = veb.successor(val);
+        }
